B.EG=new A.ca(B.re,["\u0410\u0442\u0430\u049b\u0442\u044b \u0430\u0434\u0430\u043c \u043e\u049b\u0438\u0493\u0430\u0441\u044b","\u0410\u0442\u0430\u049b\u0442\u044b \u0430\u0434\u0430\u043c\u0434\u0430\u0440\u0434\u044b\u04a3 \u0442\u0430\u0440\u0438\u0445\u0442\u0430\u0440\u044b",u.f,"\u041c\u04d9\u0441\u0435\u043b\u0435","\u0422\u043e\u043b\u044b\u049b \u043e\u049b\u0438\u0493\u0430","\u041d\u04d9\u0442\u0438\u0436\u0435","\u041d\u0435\u0433\u0456\u0437\u0433\u0456 \u0441\u0430\u0431\u0430\u049b\u0442\u0430\u0440","\u0421\u0456\u0437 \u0434\u0435 \u0436\u0430\u0441\u0430\u0439 \u0430\u043b\u0430\u0441\u044b\u0437! \ud83d\udc9a","\u041a\u04e9\u043c\u0435\u043a \u043a\u0435\u0440\u0435\u043a \u043f\u0435? \u0425\u0430\u0431\u0430\u0440\u043b\u0430\u0441\u0443\u0434\u0430\u043d \u0442\u0430\u0440\u0442\u044b\u043d\u0431\u0430\u04a3\u044b\u0437","\u041f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0442\u044b \u0442\u0430\u0431\u0443","\u0428\u04b1\u0493\u044b\u043b \u043a\u04e9\u043c\u0435\u043a",'\u0414\u0443\u044d\u0439\u043d "\u0420\u043e\u043a" \u0414\u0436\u043e\u043d\u0441\u043e\u043d',"\u0410\u043a\u0442\u0435\u0440, \u0431\u04b1\u0440\u044b\u043d\u0493\u044b \u043a\u04d9\u0441\u0456\u0431\u0438 \u0431\u0430\u043b\u0443\u0430\u043d","\u041a\u04e9\u043c\u0435\u043a \u0441\u04b1\u0440\u0430\u0443 \u04d9\u043b\u0441\u0456\u0437\u0434\u0456\u043a \u0435\u043c\u0435\u0441, \u043a\u04af\u0448","\u0410\u0448\u044b\u049b \u04d9\u04a3\u0433\u0456\u043c\u0435 \u04e9\u043c\u0456\u0440\u0434\u0456 \u04e9\u0437\u0433\u0435\u0440\u0442\u0435 \u0430\u043b\u0430\u0434\u044b","\u0411\u0430\u0441\u049b\u0430\u043b\u0430\u0440\u0493\u0430 \u043a\u04e9\u043c\u0435\u043a\u0442\u0435\u0441\u0443 \u04af\u0448\u0456\u043d \u0442\u04d9\u0436\u0456\u0440\u0438\u0431\u0435\u04a3\u0456\u0437\u0434\u0456 \u043f\u0430\u0439\u0434\u0430\u043b\u0430\u043d\u044b\u04a3\u044b\u0437",'\u2014 \u0414\u0443\u044d\u0439\u043d "\u0420\u043e\u043a" \u0414\u0436\u043e\u043d\u0441\u043e\u043d',"15 \u0436\u0430\u0441\u044b\u043d\u0434\u0430 \u0430\u0443\u044b\u0440 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u044f","\u041e\u043b \u0431\u04b1\u043b \u0442\u0443\u0440\u0430\u043b\u044b \u0430\u0448\u044b\u049b \u0430\u0439\u0442\u0443\u0434\u044b \u04af\u0439\u0440\u0435\u043d\u0434\u0456 \u0436\u04d9\u043d\u0435 \u043f\u0441\u0438\u0445\u0438\u043a\u0430\u043b\u044b\u049b \u0434\u0435\u043d\u0441\u0430\u0443\u043b\u044b\u049b\u0442\u044b \u049b\u043e\u0440\u0493\u0430\u0443\u0448\u044b\u0493\u0430 \u0430\u0439\u043d\u0430\u043b\u0434\u044b.","\u0415\u04a3 \u049b\u0438\u044b\u043d \u0441\u04d9\u0442\u0442\u0435\u0440 \u0434\u0435 \u04e9\u0442\u0435\u0434\u0456. \u04e8\u0437\u0456\u04a3\u0456\u0437\u0433\u0435 \u0434\u0435\u0433\u0435\u043d \u0441\u0435\u043d\u0456\u043c\u0434\u0456 \u0436\u043e\u0493\u0430\u043b\u0442\u043f\u0430\u04a3\u044b\u0437 \u2014 \u0441\u0456\u0437\u0434\u0456\u04a3 \u043a\u04af\u0448\u0456\u04a3\u0456\u0437 \u0441\u0456\u0437\u0434\u0456 \u0430\u043b\u0493\u0430 \u0430\u043f\u0430\u0440\u0430\u0434\u044b.",'"15 \u0436\u0430\u0441\u044b\u043c\u0434\u0430 \u043c\u0435\u043d \u0430\u043d\u0430\u043c\u043d\u044b\u04a3 \u043a\u04e9\u043b\u0456\u043a\u0442\u0435\u043d \u0448\u044b\u0493\u044b\u043f \u0431\u0430\u0440\u0430 \u0436\u0430\u0442\u049b\u0430\u043d\u0434\u0430 \u0436\u044b\u043b\u0430\u043f \u0436\u0430\u0442\u049b\u0430\u043d\u044b\u043d \u043a\u04e9\u0440\u0434\u0456\u043c. \u041c\u0435\u043d \u04b1\u0437\u0430\u049b \u0443\u0430\u049b\u044b\u0442 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u044f\u043c\u0435\u043d \u043a\u04af\u0440\u0435\u0441\u0442\u0456\u043c. \u041c\u0435\u043d \u0431\u04b1\u043b \u0442\u0443\u0440\u0430\u043b\u044b \u0430\u0439\u0442\u0443\u0434\u044b\u04a3 \u049b\u0430\u043d\u0448\u0430\u043b\u044b\u049b\u0442\u044b \u043c\u0430\u04a3\u044b\u0437\u0434\u044b \u0435\u043a\u0435\u043d\u0456\u043d \u0431\u0456\u043b\u0434\u0456\u043c \u2014 \u0431\u04b1\u043b \u04d9\u043b\u0441\u0456\u0437\u0434\u0456\u043a\u0442\u0456\u04a3 \u0431\u0435\u043b\u0433\u0456\u0441\u0456 \u0435\u043c\u0435\u0441."','\u0414\u0443\u044d\u0439\u043d \u0414\u0436\u043e\u043d\u0441\u043e\u043d \u04e9\u0437\u0456\u043d\u0456\u04a3 \u0436\u0430\u0441\u04e9\u0441\u043f\u0456\u0440\u0456\u043c \u043a\u0435\u0437\u0456\u043d\u0434\u0435 \u0430\u0443\u044b\u0440 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u044f\u043b\u044b\u049b \u049b\u0438\u044b\u043d\u0434\u044b\u049b\u0442\u0430\u0440\u0434\u044b \u0431\u0430\u0441\u0442\u0430\u043d \u043a\u0435\u0448\u0456\u0440\u0433\u0435\u043d\u0456\u043d \u0430\u0448\u044b\u049b \u043c\u043e\u0439\u044b\u043d\u0434\u0430\u0439\u0434\u044b. 15 \u0436\u0430\u0441\u044b\u043d\u0434\u0430 \u043e\u043b \u0430\u043d\u0430\u0441\u044b\u043d\u044b\u04a3 \u043a\u04af\u043d\u0434\u0435\u043b\u0456\u043a\u0442\u0456 \u04e9\u043c\u0456\u0440\u0434\u0456\u04a3 \u0430\u0443\u044b\u0440\u0442\u043f\u0430\u043b\u044b\u0493\u044b\u043d\u0430\u043d \u043c\u04af\u043b\u0434\u0435 \u0441\u044b\u043d\u044b\u043f \u0431\u0430\u0440\u0430 \u0436\u0430\u0442\u049b\u0430\u043d\u044b\u043d \u043a\u04e9\u0440\u0434\u0456. \u0421\u043e\u043b \u0441\u04d9\u0442 \u043e\u043d\u044b\u04a3 \u0436\u04af\u0440\u0435\u0433\u0456\u043d \u0436\u0430\u0440\u0434\u044b. \u041e\u043b \u04e9\u0437\u0456\u043d\u0434\u0435 \u0434\u0435 \u043e\u0441\u044b\u043d\u0434\u0430\u0439 \u0430\u0443\u044b\u0440 \u0441\u0435\u0437\u0456\u043c\u0434\u0435\u0440 \u0431\u043e\u043b\u0493\u0430\u043d\u044b\u043d \u2014 \u043c\u0430\u049b\u0441\u0430\u0442\u0441\u044b\u0437\u0434\u044b\u049b, \u04af\u043c\u0456\u0442\u0441\u0456\u0437\u0434\u0456\u043a, \u0436\u0430\u043b\u0493\u044b\u0437\u0434\u044b\u049b \u2014 \u043c\u043e\u0439\u044b\u043d\u0434\u0430\u0439\u0434\u044b.\n\n\u0410\u043b\u0430\u0439\u0434\u0430 \u0414\u0436\u043e\u043d\u0441\u043e\u043d \u043e\u0441\u044b \u0442\u04d9\u0436\u0456\u0440\u0438\u0431\u0435\u0434\u0435\u043d \u043a\u04af\u0448\u0435\u0439\u0456\u043f \u0448\u044b\u049b\u0442\u044b. \u041e\u043b \u043f\u0441\u0438\u0445\u0438\u043a\u0430\u043b\u044b\u049b \u0434\u0435\u043d\u0441\u0430\u0443\u043b\u044b\u049b \u043c\u04d9\u0441\u0435\u043b\u0435\u0441\u0456\u043d \u0436\u0430\u0440\u0438\u044f\u043b\u044b \u0442\u04af\u0440\u0434\u0435 \u0442\u0430\u043b\u049b\u044b\u043b\u0430\u0443\u0434\u044b \u0442\u0430\u04a3\u0434\u0430\u0434\u044b, \u043e\u0441\u044b\u043b\u0430\u0439\u0448\u0430 \u043c\u0438\u043b\u043b\u0438\u043e\u043d\u0434\u0430\u0493\u0430\u043d \u0430\u0434\u0430\u043c\u0493\u0430 \u2014 \u0435\u0440\u043b\u0435\u0440\u0433\u0435 \u0434\u0435, \u04d9\u0439\u0435\u043b\u0434\u0435\u0440\u0433\u0435 \u0434\u0435 \u2014 "\u041a\u04e9\u043c\u0435\u043a \u0441\u04b1\u0440\u0430\u0443\u0493\u0430 \u04b1\u044f\u043b\u043c\u0430\u04a3\u044b\u0437\u0434\u0430\u0440" \u0434\u0435\u0433\u0435\u043d \u0445\u0430\u0431\u0430\u0440\u0434\u044b \u0436\u0435\u0442\u043a\u0456\u0437\u0434\u0456.\n\n\u041e\u043d\u044b\u04a3 \u0441\u04e9\u0437\u0434\u0435\u0440\u0456: "\u04e8\u043c\u0456\u0440\u0434\u0435 \u0435\u04a3 \u049b\u0438\u044b\u043d \u0448\u0430\u0439\u049b\u0430\u0441\u0442\u0430\u0440 \u2014 \u0431\u04b1\u043b \u04e9\u0437\u0456\u04a3\u0456\u0437\u0431\u0435\u043d \u04e9\u0437\u0456\u04a3\u0456\u0437\u0434\u0456\u04a3 \u0448\u0430\u0439\u049b\u0430\u0441\u044b\u04a3\u044b\u0437. \u0411\u0456\u0440\u0430\u049b \u0441\u0456\u0437 \u0436\u0430\u043b\u0493\u044b\u0437 \u0435\u043c\u0435\u0441\u0441\u0456\u0437."'],t.li)
B.a7K=new A.ca(B.re,["\u0418\u0441\u0442\u043e\u0440\u0438\u044f \u0437\u043d\u0430\u043c\u0435\u043d\u0438\u0442\u043e\u0441\u0442\u0438","\u0418\u0441\u0442\u043e\u0440\u0438\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0445 \u043b\u044e\u0434\u0435\u0439","\u0412\u0434\u043e\u0445\u043d\u043e\u0432\u043b\u044f\u044e\u0449\u0438\u0435 \u0438\u0441\u0442\u043e\u0440\u0438\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0445 \u043b\u044e\u0434\u0435\u0439","\u041f\u0440\u043e\u0431\u043b\u0435\u043c\u0430","\u041f\u043e\u043b\u043d\u0430\u044f \u0438\u0441\u0442\u043e\u0440\u0438\u044f","\u0420\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442","\u041e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u0443\u0440\u043e\u043a\u0438","\u0412\u044b \u0442\u043e\u0436\u0435 \u043c\u043e\u0436\u0435\u0442\u0435! \ud83d\udc9a","\u041d\u0443\u0436\u043d\u0430 \u043f\u043e\u043c\u043e\u0449\u044c? \u041d\u0435 \u0441\u0442\u0435\u0441\u043d\u044f\u0439\u0442\u0435\u0441\u044c \u043e\u0431\u0440\u0430\u0449\u0430\u0442\u044c\u0441\u044f","\u041d\u0430\u0439\u0442\u0438 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0430","\u0421\u0440\u043e\u0447\u043d\u0430\u044f \u043f\u043e\u043c\u043e\u0449\u044c",'\u0414\u0443\u044d\u0439\u043d "\u0421\u043a\u0430\u043b\u0430" \u0414\u0436\u043e\u043d\u0441\u043e\u043d',"\u0410\u043a\u0442\u0451\u0440, \u0431\u044b\u0432\u0448\u0438\u0439 \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u0440\u0435\u0441\u0442\u043b\u0435\u0440","\u041f\u0440\u043e\u0441\u0438\u0442\u044c \u043e \u043f\u043e\u043c\u043e\u0449\u0438 \u2014 \u043d\u0435 \u0441\u043b\u0430\u0431\u043e\u0441\u0442\u044c, \u0430 \u0441\u0438\u043b\u0430","\u041e\u0442\u043a\u0440\u044b\u0442\u044b\u0439 \u0440\u0430\u0437\u0433\u043e\u0432\u043e\u0440 \u043c\u043e\u0436\u0435\u0442 \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0436\u0438\u0437\u043d\u044c","\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0441\u0432\u043e\u0439 \u043e\u043f\u044b\u0442, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043c\u043e\u0433\u0430\u0442\u044c \u0434\u0440\u0443\u0433\u0438\u043c",'\u2014 \u0414\u0443\u044d\u0439\u043d "\u0421\u043a\u0430\u043b\u0430" \u0414\u0436\u043e\u043d\u0441\u043e\u043d',"\u0422\u044f\u0436\u0451\u043b\u0430\u044f \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u044f \u0432 15 \u043b\u0435\u0442","\u041d\u0430\u0443\u0447\u0438\u043b\u0441\u044f \u043e\u0442\u043a\u0440\u044b\u0442\u043e \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c \u043e\u0431 \u044d\u0442\u043e\u043c, \u0441\u0442\u0430\u043b \u0437\u0430\u0449\u0438\u0442\u043d\u0438\u043a\u043e\u043c \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f.","\u0414\u0430\u0436\u0435 \u0441\u0430\u043c\u044b\u0435 \u0442\u0451\u043c\u043d\u044b\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0430 \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0442. \u041d\u0435 \u0442\u0435\u0440\u044f\u0439\u0442\u0435 \u0432\u0435\u0440\u044b \u0432 \u0441\u0435\u0431\u044f \u2014 \u0432\u0430\u0448\u0430 \u0441\u0438\u043b\u0430 \u0432\u0435\u0434\u0451\u0442 \u0432\u0430\u0441 \u0432\u043f\u0435\u0440\u0451\u0434.",'"\u0412 15 \u043b\u0435\u0442 \u044f \u0432\u0438\u0434\u0435\u043b, \u043a\u0430\u043a \u043c\u043e\u044f \u043c\u0430\u0442\u044c \u0432\u044b\u0445\u043e\u0434\u0438\u043b\u0430 \u0438\u0437 \u043c\u0430\u0448\u0438\u043d\u044b \u0438 \u043f\u043b\u0430\u043a\u0430\u043b\u0430. \u042f \u0434\u043e\u043b\u0433\u043e \u0431\u043e\u0440\u043e\u043b\u0441\u044f \u0441 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u0435\u0439. \u042f \u043f\u043e\u043d\u044f\u043b, \u043a\u0430\u043a \u0432\u0430\u0436\u043d\u043e \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c \u043e\u0431 \u044d\u0442\u043e\u043c \u2014 \u044d\u0442\u043e \u043d\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u0441\u043b\u0430\u0431\u043e\u0441\u0442\u0438."','\u0414\u0443\u044d\u0439\u043d \u0414\u0436\u043e\u043d\u0441\u043e\u043d \u043e\u0442\u043a\u0440\u044b\u0442\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u0451\u0442, \u0447\u0442\u043e \u0432 \u043f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u043e\u043c \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0435 \u043f\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043b \u0442\u044f\u0436\u0451\u043b\u044b\u0435 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0442\u0440\u0443\u0434\u043d\u043e\u0441\u0442\u0438. \u0412 15 \u043b\u0435\u0442 \u043e\u043d \u0441\u0442\u0430\u043b \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043b\u0435\u043c \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0435\u0433\u043e \u043c\u0430\u0442\u044c \u0431\u044b\u043b\u0430 \u0441\u043b\u043e\u043c\u043b\u0435\u043d\u0430 \u0442\u044f\u0436\u0435\u0441\u0442\u044c\u044e \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438. \u042d\u0442\u043e\u0442 \u043c\u043e\u043c\u0435\u043d\u0442 \u0440\u0430\u0437\u0431\u0438\u043b \u0435\u043c\u0443 \u0441\u0435\u0440\u0434\u0446\u0435. \u041e\u043d \u043f\u0440\u0438\u0437\u043d\u0430\u0451\u0442, \u0447\u0442\u043e \u0438 \u0441\u0430\u043c \u0438\u0441\u043f\u044b\u0442\u044b\u0432\u0430\u043b \u043f\u043e\u0434\u043e\u0431\u043d\u044b\u0435 \u0442\u044f\u0436\u0451\u043b\u044b\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u2014 \u0431\u0435\u0441\u0446\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0431\u0435\u0437\u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0441\u0442\u044c, \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u043e.\n\n\u041e\u0434\u043d\u0430\u043a\u043e \u0414\u0436\u043e\u043d\u0441\u043e\u043d \u0432\u044b\u0448\u0435\u043b \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u043e\u043f\u044b\u0442\u0430 \u0441\u0438\u043b\u044c\u043d\u0435\u0435. \u041e\u043d \u0432\u044b\u0431\u0440\u0430\u043b \u043f\u0443\u0442\u044c \u043e\u0442\u043a\u0440\u044b\u0442\u043e\u0433\u043e \u043e\u0431\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u044f \u043f\u0440\u043e\u0431\u043b\u0435\u043c \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f, \u0434\u043e\u043d\u043e\u0441\u044f \u0434\u043e \u043c\u0438\u043b\u043b\u0438\u043e\u043d\u043e\u0432 \u043b\u044e\u0434\u0435\u0439 \u2014 \u043c\u0443\u0436\u0447\u0438\u043d \u0438 \u0436\u0435\u043d\u0449\u0438\u043d \u2014 \u043f\u043e\u0441\u043b\u0430\u043d\u0438\u0435: "\u041d\u0435 \u0441\u0442\u0435\u0441\u043d\u044f\u0439\u0442\u0435\u0441\u044c \u043f\u0440\u043e\u0441\u0438\u0442\u044c \u043e \u043f\u043e\u043c\u043e\u0449\u0438".\n\n\u0415\u0433\u043e \u0441\u043b\u043e\u0432\u0430: "\u0421\u0430\u043c\u044b\u0435 \u0442\u044f\u0436\u0451\u043b\u044b\u0435 \u0431\u0438\u0442\u0432\u044b \u0432 \u0436\u0438\u0437\u043d\u0438 \u2014 \u044d\u0442\u043e \u0431\u0438\u0442\u0432\u044b \u0441 \u0441\u0430\u043c\u0438\u043c \u0441\u043e\u0431\u043e\u0439. \u041d\u043e \u0432\u044b \u043d\u0435 \u043e\u0434\u043d\u0438."'],t.li)
B.a7J=new A.ca(B.re,["Famous Person Story","Stories of Famous People","Inspiring stories of famous people","Problem","Full Story","Result","Key Lessons","You Can Do It Too! \ud83d\udc9a","Need help? Don't hesitate to reach out","Find a Psychologist","Emergency Help",'Dwayne "The Rock" Johnson',"Actor, former professional wrestler","Asking for help is strength, not weakness","An open conversation can change your life","Use your experience to help others",'\u2014 Dwayne "The Rock" Johnson',"Severe depression at age 15","Learned to speak openly about it, became an advocate for mental health.","Even the darkest times pass. Never lose faith in yourself \u2014 your strength carries you forward.",'"At 15, I watched my mom walk out of the car crying. I struggled with depression for a long time. I realized how important it is to talk about it \u2014 it\'s not a sign of weakness."','Dwayne Johnson openly admits that he went through severe psychological difficulties during his teenage years. At 15, he witnessed his mother completely broken by the weight of daily life. That moment shattered his heart. He acknowledges that he too experienced those heavy feelings \u2014 purposelessness, hopelessness, loneliness.\n\nYet Johnson emerged from this experience stronger. He chose to publicly discuss mental health, delivering a message to millions of people \u2014 men and women alike \u2014 "Don\'t be ashamed to ask for help."\n\nHis words: "The toughest battles in life are with yourself. But you are not alone."'],t.li)
